  ('police-f3743df6-moex-00120', 'police-f3743df6', 'police-f3743df6-moex-113-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依司法院釋字第688號解釋，立法者於制定法律時，創設一具有體系規範意義之法律原則時 ，除有基於重大公益之考量外，應受其原則拘束以維持法律體系之一貫性，是為體系之正義 。其後立法有違背此體系正義時，係違反下列何原則？', '["比例原則", "平等原則", "信賴保護原則", "誠信原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:18+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "512", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
