  ('police-f3743df6-moex-00123', 'police-f3743df6', 'police-f3743df6-moex-113-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '關於總統、副總統之缺位或不能視事，下列敘述何者錯誤？', '["總統缺位時，由副總統繼任，至總統任期屆滿為止", "副總統缺位時，總統應於3個月內提名候選人，由立法院補選，繼任至原任期屆滿為止", "總統、副總統均缺位時，由行政院院長代行其職權，至原任期屆滿為止", "總統、副總統均不能視事時，由行政院院長代行其職權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:18+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "512", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00124', 'police-f3743df6', 'police-f3743df6-moex-113-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依憲法增修條文第2條第5項關於解散立法院之規定，總統於立法院通過對於行政院院長之 不信任案後10日內，經諮詢何人後，得宣告解散立法院？', '["行政院院長", "立法院院長", "司法院院長", "監察院院長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:18+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "512", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
